def generate_fact_ar(entry):
    cid = entry["id"].lower()
    if cid in FACTS:
        return FACTS[cid]
    # Generic but informative Arabic fallback
    country = entry.get("country_ar") or entry.get("country", "")
    capital = entry.get("capital_ar") or entry.get("capital", "")
    continent = entry.get("continent", "")
    continent_ar = {
        "Asia": "آسيا", "Africa": "أفريقيا", "Europe": "أوروبا",
        "Americas": "أمريكا", "Oceania": "أوقيانوسيا", "North America": "أمريكا الشمالية",
        "South America": "أمريكا الجنوبية", "Central America": "أمريكا الوسطى",
        "Caribbean": "الكاريبي",
    }.get(continent, continent)
    if continent_ar:
        return f"{capital} عاصمة {country} الواقعة في قارة {continent_ar}."
    return f"{capital} هي العاصمة الرسمية لدولة {country}."

def main():
    path = "assets/data/capitals.json"
    with open(path, "r", encoding="utf-8") as f:
        data = json.load(f)

    fixed = 0
    for entry in data:
        ff = entry.get("fun_fact", "")
        if "located at latitude" in ff or "located at lat" in ff:
            entry["fun_fact"] = generate_fact_ar(entry)
            fixed += 1

    with open(path, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)

    print(f"Fixed {fixed} fun facts out of {len(data)} entries.")

if __name__ == "__main__":
    main()
